import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Trash, ArrowLeft, 
  Eye, X, ShoppingBasket, Edit2, Check, Calendar
} from 'lucide-react';
import SubirImagenes from './SubirImagenes'; 

const API_URL = "http://localhost:5000"; 
const CLOUD_NAME = "dwpgncjgn";

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const filaInicial = () => ({ 
    id: Math.random(), 
    producto: '', 
    precioNuevo: '', 
    precioViejo: '', 
    stock: '', 
    categoria: 'Almacén', 
    fotoSugerida: null 
  });
  
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [mostrarGaleria, setMostrarGaleria] = useState(false);
  const [editandoId, setEditandoId] = useState(null);
  const [formEdit, setFormEdit] = useState({});

  const cargarDatos = useCallback(async () => {
    try {
      const [resOfertas, resGaleria] = await Promise.all([
        axios.get(`${API_URL}/api/ofertas/local/${localId}`),
        axios.get(`${API_URL}/api/galeria`)
      ]);
      setPublicados(resOfertas.data || []);
      setGaleria(resGaleria.data || []);
    } catch (e) { console.error("Error al sincronizar", e); }
  }, [localId]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    const norm = (t) => t.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]/g, '');
    const textoLimpio = norm(texto);
    return galeria.find(f => {
      const refLimpia = norm(f.nombreReferencia.split('.')[0]); 
      return refLimpia.includes(textoLimpio) || textoLimpio.includes(refLimpia);
    });
  }, [galeria]);

  // --- LÓGICA DE PEGADO DISTRIBUIDO ---
  const handlePaste = (e) => {
    const pasteData = e.clipboardData.getData('text');
    
    // Si el texto tiene tabulaciones (viene de Excel/Sheets)
    if (pasteData.includes('\t') || pasteData.includes('\n')) {
      e.preventDefault(); // Evitamos que se pegue todo en el primer input
      
      const lineas = pasteData.split(/\r?\n/).filter(l => l.trim() !== '');
      
      const nuevasFilas = lineas.map(line => {
        const columnas = line.split('\t');
        const nombre = columnas[0]?.trim() || '';
        const match = buscarMatch(nombre);

        return {
          id: Math.random(),
          producto: nombre,
          precioNuevo: columnas[1]?.replace(/[^0-9.]/g, '') || '',
          precioViejo: columnas[2]?.replace(/[^0-9.]/g, '') || '',
          stock: columnas[3]?.replace(/[^0-9]/g, '') || '0',
          categoria: columnas[4]?.trim() || 'Almacén',
          fotoSugerida: match ? match.publicId : null
        };
      });

      // Si pegamos algo, reemplazamos las filas actuales (o las añadimos)
      setFilas(nuevasFilas);
    }
  };

  const handleInputChange = (id, campo, valor) => {
    setFilas(filas.map(f => {
      if (f.id === id) {
        const act = { ...f, [campo]: valor };
        if (campo === 'producto') {
          const m = buscarMatch(valor);
          act.fotoSugerida = m ? m.publicId : null;
        }
        return act;
      }
      return f;
    }));
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Selecciona fechas de validez.");
    const validas = filas.filter(f => f.producto && f.precioNuevo);
    if (validas.length === 0) return alert("No hay productos válidos.");

    setCargando(true);
    try {
      const productos = validas.map(f => ({
        ...f,
        publicId: f.fotoSugerida || 'placeholder_id',
        fechaInicioOferta: fechas.inicio,
        fechaFinOferta: fechas.fin,
        publicado: true
      }));
      await axios.post(`${API_URL}/api/ofertas/bulk`, { localId, productos });
      setFilas([filaInicial()]);
      cargarDatos();
      alert("¡Ofertas publicadas!");
    } catch (e) { alert("Error al publicar."); } finally { setCargando(false); }
  };

  const renderFoto = (pid, size = "w_150,h_150") => {
    if (!pid || pid === 'placeholder_id') return <div style={thumbPlaceholder}><ImageIcon color="#cbd5e1" size={20}/></div>;
    const urlFinal = `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/${size},c_fill,f_auto,q_auto/${pid}`;
    return (
      <div style={thumbWrap}>
        <img src={urlFinal} style={imgStyle} alt="P" />
      </div>
    );
  };

  const tandas = publicados.reduce((acc, p) => {
    const fecha = p.fechaFinOferta ? new Date(p.fechaFinOferta).toLocaleDateString() : 'Sin Fecha';
    if (!acc[fecha]) acc[fecha] = [];
    acc[fecha].push(p);
    return acc;
  }, {});

  return (
    <div style={containerStyle}>
      <div style={navStyle}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver al Mapa</button>
        <div style={{ display: 'flex', gap: '12px' }}>
            <button onClick={() => setMostrarGaleria(!mostrarGaleria)} style={btnVerGaleria}><Eye size={18}/> Biblioteca</button>
            <SubirImagenes onFinished={cargarDatos} />
        </div>
      </div>

      <header style={{ marginBottom: '30px' }}>
        <h1 style={titleStyle}><ShoppingBasket color="#e67e22" size={32}/> Gestión de Inventario</h1>
        <p style={{color: '#64748b'}}>Copia de Excel y pega directamente en el cuadro de "Producto".</p>
      </header>

      {/* SECCIÓN CARGA MASIVA */}
      <section style={cardContainer}>
        <div style={cardHeader}>
          <div style={{ color: '#e67e22', fontWeight: 'bold' }}>Carga Masiva</div>
          <button onClick={() => setFilas([...filas, filaInicial()])} style={btnAddRow}><Plus size={16}/> Nueva Fila</button>
        </div>
        <div style={{overflowX: 'auto'}}>
          <table style={tableStyle}>
            <thead>
              <tr style={tableHead}>
                <th style={thStyle}>Foto</th>
                <th style={thStyle}>Producto (Pegar aquí)</th>
                <th style={thStyle}>$ Oferta</th>
                <th style={thStyle}>$ Viejo</th>
                <th style={thStyle}>Stock</th>
                <th style={thStyle}>Categoría</th>
                <th style={{width: 50}}></th>
              </tr>
            </thead>
            <tbody>
              {filas.map(f => (
                <tr key={f.id} style={trStyle}>
                  <td style={tdStyle}>{renderFoto(f.fotoSugerida)}</td>
                  <td style={tdStyle}>
                    <input 
                      style={inputTable} 
                      value={f.producto} 
                      placeholder="Pega aquí tu Excel..." 
                      onPaste={handlePaste}
                      onChange={e => handleInputChange(f.id, 'producto', e.target.value)}
                    />
                  </td>
                  <td style={tdStyle}><input style={inputNum} value={f.precioNuevo} onChange={e => handleInputChange(f.id, 'precioNuevo', e.target.value)}/></td>
                  <td style={tdStyle}><input style={inputNum} value={f.precioViejo} onChange={e => handleInputChange(f.id, 'precioViejo', e.target.value)}/></td>
                  <td style={tdStyle}><input style={inputNum} value={f.stock} onChange={e => handleInputChange(f.id, 'stock', e.target.value)}/></td>
                  <td style={tdStyle}><input style={inputTable} value={f.categoria} onChange={e => handleInputChange(f.id, 'categoria', e.target.value)}/></td>
                  <td style={tdStyle}><button onClick={() => setFilas(filas.filter(x => x.id !== f.id))} style={btnX}><X size={18}/></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={cardFooter}>
          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
            <Calendar size={18} color="#64748b"/>
            <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={inputDate}/>
            <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={inputDate}/>
          </div>
          <button onClick={publicarTodo} style={btnPublish} disabled={cargando}>
            {cargando ? <Loader2 className="animate-spin"/> : "SUBIR TODO"}
          </button>
        </div>
      </section>

      {/* RENDERIZADO DE TANDAS ACTIVAS */}
      {Object.keys(tandas).map(fecha => (
        <div key={fecha} style={{ marginBottom: '40px' }}>
          <div style={tandaHeader}>Vence: {fecha}</div>
          <div style={gridStyle}>
            {tandas[fecha].map(p => (
              <div key={p._id} style={itemCard}>
                <div style={itemActions}>
                    <button onClick={async () => { if(window.confirm("¿Borrar?")){ await axios.delete(`${API_URL}/api/ofertas/${p._id}`); cargarDatos(); }}} style={btnDel}><Trash size={14}/></button>
                </div>
                <div style={itemPreview}>{renderFoto(p.publicId, "w_200,h_150")}</div>
                <h4 style={itemTitle}>{p.producto}</h4>
                <div style={{textAlign:'center'}}><span style={newPrice}>${p.precioNuevo}</span></div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

// ESTILOS (Mantenidos y optimizados)
const containerStyle = { padding: '30px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif' };
const navStyle = { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' };
const btnBack = { background: 'none', border: 'none', cursor: 'pointer', display:'flex', alignItems:'center', gap:5, color:'#64748b' };
const btnVerGaleria = { background: 'white', border: '1px solid #e2e8f0', padding: '8px 15px', borderRadius: '10px', cursor:'pointer', display:'flex', alignItems:'center', gap:5 };
const titleStyle = { margin: 0, display: 'flex', alignItems: 'center', gap: 10 };
const cardContainer = { background: 'white', borderRadius: '15px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '30px' };
const cardHeader = { padding: '15px', borderBottom: '1px solid #f1f5f9', display: 'flex', justifyContent: 'space-between' };
const btnAddRow = { background: '#f1f5f9', border: 'none', padding: '5px 12px', borderRadius: '8px', cursor: 'pointer' };
const tableStyle = { width: '100%', borderCollapse: 'collapse' };
const tableHead = { background: '#f8fafc' };
const thStyle = { padding: '12px', textAlign: 'left', fontSize: '0.75rem', color: '#64748b' };
const trStyle = { borderBottom: '1px solid #f1f5f9' };
const tdStyle = { padding: '10px' };
const inputTable = { width: '100%', border: '1px solid transparent', padding: '5px', outline: 'none' };
const inputNum = { width: '70px', padding: '5px', border: '1px solid #e2e8f0', borderRadius: '5px' };
const cardFooter = { padding: '15px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc' };
const inputDate = { padding: '5px', borderRadius: '5px', border: '1px solid #e2e8f0' };
const btnPublish = { background: '#e67e22', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };
const tandaHeader = { background: '#1e293b', color: 'white', padding: '8px 15px', borderRadius: '8px', marginBottom: '15px', display:'inline-block', fontSize:'0.8rem' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' };
const itemCard = { background: 'white', padding: '15px', borderRadius: '15px', border: '1px solid #e2e8f0', position:'relative' };
const itemActions = { position:'absolute', top:10, right:10 };
const btnDel = { background:'#fee2e2', border:'none', borderRadius:'50%', width:'30px', height:'30px', color:'#ef4444', cursor:'pointer' };
const itemPreview = { height:'100px', display:'flex', justifyContent:'center', marginBottom:'10px' };
const itemTitle = { fontSize:'0.9rem', margin:'0 0 5px 0', textAlign:'center' };
const newPrice = { fontWeight:'bold', color:'#e67e22' };
const thumbWrap = { width: 50, height: 50, borderRadius: 8, overflow: 'hidden', border: '1px solid #e2e8f0' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'contain' };
const thumbPlaceholder = { width: 50, height: 50, background: '#f1f5f9', borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center' };
const btnX = { border:'none', background:'none', cursor:'pointer', color:'#cbd5e1' };

export default GestionOfertas;
